#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long M; scanf("%d %lld", &N, &M);
        long long cur=0, ans=0;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            cur+=x;
            if(cur>=M){ ans++; cur=0; }
        }
        if(ans==0) ans=1; // whole array forms one state
        printf("%lld\n", ans);
    }
    return 0;
}

