#!/usr/bin/env python3
import sys
def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); M = next(it)
        cur = 0
        ans = 0
        for _ in range(N):
            x = next(it)
            cur += x
            if cur >= M:
                ans += 1
                cur = 0
        if ans == 0:
            ans = 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

